package com.example.app.waitlist; import com.example.app.common.BaseEntity; import jakarta.persistence.*; import lombok.Getter; import lombok.Setter; import java.time.*; @Getter @Setter @Entity @Table(name="waitlist_request_window") public class WaitlistRequestWindow extends BaseEntity { @ManyToOne(optional=false) @JoinColumn(name="waitlist_request_id") private WaitlistRequest request; @Column(name="day_of_week") private Integer dayOfWeek; @Column(name="requested_date") private LocalDate date; @Column(name="time_from") private LocalTime timeFrom; @Column(name="time_to") private LocalTime timeTo; }